#include <bits/stdc++.h>
using namespace std;

const int mod=1e9+7,N=1e5+10;

struct Edge{
    int u,v;
}edge[30];

int n,m,q,dp[1<<15][18],f[N],d[18],inv[18],s[30],stk[30][3],top;
bool b[1<<15],vis[N];
vector<int> e[N],r;

int C(int n,int m){
    if(m<0 || n<m) return 0;
    int res=1;
    for(int i=1;i<=m;i++)
        res=1ll*res*(n-i+1)%mod*inv[i]%mod;
    return res;
}

int father(int x){
    return f[x]<0?x:father(f[x]);
}

bool Merge(int x,int y){
    int fx=father(x),fy=father(y);
    if(fx!=fy){
        if(f[fx]>f[fy]) swap(fx,fy);
        top++;
        stk[top][0]=fx,stk[top][1]=fy,stk[top][2]=f[fy];
        f[fx]+=f[fy],f[fy]=fx;
        return true;
    }
    return false;
}

void Split(){
    int x=stk[top][0],y=stk[top][1],z=stk[top][2];
    f[x]-=z,f[y]=z;
    top--;
}

int qpow(int a,int b){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base%mod;
        base=base*base%mod,b>>=1;
    }
    return ans;
}

void dfs(int x,int len){
    len++;
    vis[x]=1;
    bool flag=true;
    for(int y:e[x])
        if(!vis[y]){
            dfs(y,len);
            flag=false;
        }
    if(flag)
        r.push_back(len);
}

void dfs2(int x,int ones){
    if(x>m){
        if(ones%2) s[top]--;
        else s[top]++;
        return;
    }
    dfs2(x+1,ones);
    bool flag=Merge(edge[x].u,edge[x].v);
    dfs2(x+1,ones+1);
    if(flag)
        Split();
}

int main(){
    scanf("%d%d%d",&n,&m,&q);
    if(n<=15){
        inv[0]=inv[1]=1;
        for(int i=2;i<=n;i++)
            inv[i]=1ll*(mod-mod/i)*inv[mod%i]%mod;
        for(int i=1;i<=m;i++){
            int u,v;
            scanf("%d%d",&u,&v);
            d[u]|=1<<v-1;
            d[v]|=1<<u-1;
        }
        for(int i=1;i<1<<n;i++)
            for(int j=1;j<=n;j++)
                if(((i>>j-1)&1) && (i&d[j]))
                    b[i]=1;
        dp[0][0]=1;
        for(int i=1;i<1<<n;i++)
            for(int j=1;j<=n;j++)
                for(int k=i;k;k=(k-1)&i)
                    if(!b[k])
                        dp[i][j]=(dp[i][j]+dp[i^k][j-1])%mod;
        while(q--){
            int k,ans=0;
            scanf("%d",&k);
            for(int i=1;i<=n;i++)
                ans=(ans+1ll*dp[(1<<n)-1][i]*C(k,i))%mod;
            printf("%d\n",ans);
        }
    }else if(m<=24){
        for(int i=1;i<=m;i++)
            scanf("%d%d",&edge[i].u,&edge[i].v);
        for(int i=1;i<=n;i++)
            f[i]=-1;
        dfs2(1,0);
        while(q--){
            int k,ans=0;
            scanf("%d",&k);
            for(int i=0;i<=m;i++)
                if(s[i])
                    ans=(ans+1ll*s[i]*qpow(k,n-i))%mod;
            printf("%d\n",(ans+mod)%mod);
        }
    }else{
        for(int i=1,u,v;i<=m;i++){
            scanf("%d%d",&u,&v);
            e[u].push_back(v);
            e[v].push_back(u);
        }
        for(int i=1;i<=n;i++)
            if(!vis[i])
                dfs(i,0);
        while(q--){
            int k,ans=1;
            scanf("%d",&k);
            f[1]=k,f[2]=1ll*k*(k-1)%mod;
            for(int i=3,num=1ll*f[2]*(k-1)%mod;i<=n;i++,num=1ll*num*(k-1)%mod)
                f[i]=(num-f[i-1])%mod;
            for(int i:r)
                ans=1ll*ans*f[i]%mod;
            printf("%d\n",(ans+mod)%mod);
        }
    }
    return 0;
}
